import { Card, CardContent } from "@/shared/component/ui/card";
import { Skeleton } from "@/shared/component/ui/skeleton";

const CariCardSkeleton = () => {
  return (
    <Card className="border-2 border-green-900 pt-0 pb-3 shadow-[8px_8px_0px_0px_#0f301060] md:pb-6">
      <Skeleton className="h-22 w-full rounded-b-none md:h-45" />
      <CardContent className="flex flex-col justify-between px-2 md:px-4">
        <div className="flex h-23 flex-col gap-2 md:h-40 md:gap-3">
          <Skeleton className="h-3 w-4/5 md:h-6" />
          <Skeleton className="h-3 w-2/3 md:h-5" />
          <div className="flex items-center gap-2">
            <Skeleton className="h-4 w-16 rounded-full md:h-6 md:w-20" />
            <Skeleton className="h-4 w-20 rounded-full md:h-6 md:w-28" />
          </div>
          <div className="flex items-center gap-2">
            <Skeleton className="h-4 w-14 rounded-full md:h-6 md:w-16" />
            <Skeleton className="h-4 w-14 rounded-full md:h-6 md:w-16" />
          </div>
        </div>
        <Skeleton className="h-6 w-full rounded-full md:h-11" />
      </CardContent>
    </Card>
  );
};

export default CariCardSkeleton;

"use client";

import { SupplierData } from "@/feature/supplier/cari/data/data";
import Kategori from "@/feature/supplier/cari/components/Kategori";
import CariCard from "@/feature/supplier/cari/components/CariCard";
import { Button } from "@/shared/component/ui/button";
import { ChevronDown } from "lucide-react";
import { useState } from "react";
import { ScrollArea } from "@/shared/component/ui/scroll-area";

const CariSection = () => {
  const [showAll, setShowAll] = useState(false);

  const displayed = showAll ? SupplierData : SupplierData.slice(0, 9);

  return (
    <section className="mt-40">
      <Kategori />

      <div className="mt-15 w-full rounded-t-[56px] border-t-4 border-green-900 bg-green-50 py-12 md:mt-30 md:rounded-t-[100px] md:py-20">
        <div className="mx-auto mb-10 w-[90%] md:mb-20 md:w-[85%]">
          <div className="max-w-[60%] rounded-[40px] border-2 border-green-900 bg-white p-3 px-6 md:max-w-[35%]">
            <h1 className="text-center text-[12px] font-bold text-green-900 md:text-4xl">
              Supplier Terpopuler
            </h1>
          </div>
        </div>
        <div className="mx-auto w-[90%] md:w-[85%]">
          <ScrollArea
            type="always"
            className="h-100 pr-1 **:data-[slot=scroll-area-scrollbar]:rounded-full **:data-[slot=scroll-area-scrollbar]:bg-green-100 **:data-[slot=scroll-area-thumb]:bg-green-600 **:data-[slot=scroll-area-thumb]:hover:bg-green-700 md:h-200 md:pr-8"
          >
            <div className="pr-6 pb-6">
              <div className="grid grid-cols-2 gap-x-5 gap-y-5 md:grid-cols-3 md:gap-x-6 md:gap-y-16">
                {displayed.map((item) => (
                  <CariCard
                    key={item.id}
                    title={item.title}
                    address={item.address}
                    category={item.category}
                  />
                ))}
              </div>
            </div>
          </ScrollArea>
        </div>

        {!showAll && (
          <div className="mx-auto mt-10 mb-10 w-[90%] md:mt-20 md:mb-20 md:w-[85%]">
            <Button
              className="flex w-[50%] cursor-pointer items-center justify-center rounded-[40px] bg-green-500 py-3 hover:scale-105 md:w-[25%] md:py-6"
              onClick={() => setShowAll(true)}
            >
              <p className="text-[8px] font-bold md:text-xl">
                Tampilkan lebih banyak
              </p>
              <ChevronDown className="h-3 w-3 md:h-12 md:w-12" />
            </Button>
          </div>
        )}
      </div>
    </section>
  );
};

export default CariSection;

"use client";

import { SupplierData } from "@/feature/supplier/cari/data/data";
import Kategori from "@/feature/supplier/cari/components/Kategori";
import CariCard from "@/feature/supplier/cari/components/CariCard";
import CariCardSkeleton from "@/feature/supplier/cari/components/CariCardSkeleton";
import { Button } from "@/shared/component/ui/button";
import { ChevronDown } from "lucide-react";
import { useEffect, useMemo, useState } from "react";
import { ScrollArea } from "@/shared/component/ui/scroll-area";

const INITIAL_BATCH = 9;

const CariSection = () => {
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [showAll, setShowAll] = useState(false);
  const [isInitialLoading, setIsInitialLoading] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => setIsInitialLoading(false), 800);
    return () => clearTimeout(timer);
  }, []);

  const filteredSuppliers = useMemo(() => {
    if (!selectedCategory) return SupplierData;

    return SupplierData.filter((item) =>
      item.category.some(
        (cat) => cat.toLowerCase() === selectedCategory.toLowerCase(),
      ),
    );
  }, [selectedCategory]);

  const displayed = showAll
    ? filteredSuppliers
    : filteredSuppliers.slice(0, INITIAL_BATCH);
  const hasMore = displayed.length < filteredSuppliers.length;

  const handleCategoryChange = (category: string | null) => {
    setSelectedCategory(category);
    setShowAll(false);
  };

  return (
    <section className="mt-40">
      <Kategori
        activeCategory={selectedCategory}
        onCategoryChange={handleCategoryChange}
      />

      <div className="mt-15 w-full rounded-t-[56px] border-t-4 border-green-900 bg-green-50 py-12 md:mt-30 md:rounded-t-[100px] md:py-20">
        <div className="mx-auto mb-10 w-[90%] md:mb-20 md:w-[85%]">
          <div className="max-w-[60%] rounded-[40px] border-2 border-green-900 bg-white p-3 px-6 md:max-w-[35%]">
            <h1 className="text-center text-[12px] font-bold text-green-900 md:text-4xl">
              Supplier Terpopuler
            </h1>
          </div>
        </div>
        <div className="mx-auto w-[90%] md:w-[85%]">
          <ScrollArea
            type="always"
            className="h-100 pr-1 **:data-[slot=scroll-area-scrollbar]:rounded-full **:data-[slot=scroll-area-scrollbar]:bg-green-100 **:data-[slot=scroll-area-thumb]:bg-green-600 **:data-[slot=scroll-area-thumb]:hover:bg-green-700 md:h-200 md:pr-8"
          >
            <div className="pr-6 pb-6">
              <div className="grid grid-cols-2 gap-x-5 gap-y-5 md:grid-cols-3 md:gap-x-6 md:gap-y-16">
                {isInitialLoading &&
                  Array.from({ length: INITIAL_BATCH }).map((_, index) => (
                    <CariCardSkeleton key={`initial-skeleton-${index}`} />
                  ))}

                {!isInitialLoading &&
                  displayed.map((item) => (
                    <CariCard
                      key={item.id}
                      title={item.title}
                      address={item.address}
                      category={item.category}
                    />
                  ))}

                {!isInitialLoading && displayed.length === 0 && (
                  <div className="col-span-2 rounded-2xl border-2 border-dashed border-green-800 bg-white p-6 text-center text-sm font-semibold text-green-900 md:col-span-3 md:text-lg">
                    Tidak ada supplier untuk kategori ini.
                  </div>
                )}

              </div>
            </div>
          </ScrollArea>
        </div>

        {!isInitialLoading && hasMore && (
          <div className="mx-auto mt-10 mb-10 w-[90%] md:mt-20 md:mb-20 md:w-[85%]">
            <Button
              className="flex w-[50%] cursor-pointer items-center justify-center rounded-[40px] bg-green-500 py-3 hover:scale-105 md:w-[25%] md:py-6"
              onClick={() => setShowAll(true)}
            >
              <p className="text-[8px] font-bold md:text-xl">Tampilkan semuanya</p>
              <ChevronDown className="h-3 w-3 md:h-12 md:w-12" />
            </Button>
          </div>
        )}
      </div>
    </section>
  );
};

export default CariSection;

import { Card } from "@/shared/component/ui/card";
import { Beef, Carrot, Citrus, Milk } from "lucide-react";
import { useFormStore } from "@/shared/store/useFormStore";

const categories = [
  { name: "Daging", icon: Beef },
  { name: "Sayur", icon: Carrot },
  { name: "Buah", icon: Citrus },
  { name: "Hasil Ternak", icon: Milk },
];

const Kategori = () => {
  const { category, setCategory, setStep } = useFormStore();

  return (
    <div className="mx-auto mb-12 grid h-[50%] w-[90%] grid-cols-4 gap-4 md:w-[70%] md:gap-0">
      {categories.map((item) => {
        const Icon = item.icon;
        const isActive = category === item.name;

        return (
          <div
            key={item.name}
            className="relative mx-auto w-full max-w-20 md:max-w-40"
          >
            <div
              className={`absolute inset-0 translate-x-1 translate-y-1 rounded-xl md:translate-x-2 md:translate-y-2 md:rounded-3xl ${
                isActive ? "bg-green-900" : "border-2 border-green-900"
              }`}
            />

            <Card
              onClick={() => {
                setCategory(item.name);
                setStep(3);
              }}
              className={`relative flex w-full cursor-pointer flex-col items-center justify-center gap-2 rounded-xl border-2 border-green-900 transition-all duration-200 active:translate-x-1 active:translate-y-1 md:gap-4 md:rounded-3xl md:active:translate-x-2 md:active:translate-y-2 ${
                isActive
                  ? "shadow-[3px_3px_0px_0px_var(--color-green-900)] md:shadow-[6px_6px_0px_0px_var(--color-green-900)]"
                  : "bg-white"
              }`}
            >
              <div className="rounded-full bg-orange-600 p-1 text-orange-50 md:p-4">
                <Icon className="h-4 w-4 md:h-7.5 md:w-7.5" />
              </div>

              <p className="text-[8px] font-semibold md:text-lg">{item.name}</p>
            </Card>
          </div>
        );
      })}
    </div>
  );
};

export default Kategori;

"use client";

import { Card } from "@/shared/component/ui/card";
import { Beef, Carrot, Citrus, Milk } from "lucide-react";

const categories = [
  { name: "Daging", icon: Beef },
  { name: "Sayur", icon: Carrot },
  { name: "Buah", icon: Citrus },
  { name: "Hasil Ternak", icon: Milk },
];

type Props = {
  activeCategory: string | null;
  onCategoryChange: (category: string | null) => void;
};

const Kategori = ({ activeCategory, onCategoryChange }: Props) => {

  return (
    <div className="mx-auto mb-12 grid h-[50%] w-[90%] grid-cols-4 gap-4 md:w-[70%] md:gap-0">
      {categories.map((item) => {
        const Icon = item.icon;
        const isActive = activeCategory === item.name;

        return (
          <div
            key={item.name}
            className="relative mx-auto w-full max-w-20 md:max-w-40"
          >
            <div
              className={`absolute inset-0 translate-x-1 translate-y-1 rounded-xl md:translate-x-2 md:translate-y-2 md:rounded-3xl ${
                isActive ? "bg-green-900" : "border-2 border-green-900"
              }`}
            />

            <Card
              onClick={() => {
                onCategoryChange(isActive ? null : item.name);
              }}
              className={`relative flex w-full cursor-pointer flex-col items-center justify-center gap-2 rounded-xl border-2 border-green-900 transition-all duration-200 active:translate-x-1 active:translate-y-1 md:gap-4 md:rounded-3xl md:active:translate-x-2 md:active:translate-y-2 ${
                isActive
                  ? "shadow-[3px_3px_0px_0px_var(--color-green-900)] md:shadow-[6px_6px_0px_0px_var(--color-green-900)]"
                  : "bg-white"
              }`}
            >
              <div className="rounded-full bg-orange-600 p-1 text-orange-50 md:p-4">
                <Icon className="h-4 w-4 md:h-7.5 md:w-7.5" />
              </div>

              <p className="text-[8px] font-semibold md:text-lg">{item.name}</p>
            </Card>
          </div>
        );
      })}
    </div>
  );
};

export default Kategori;
